/**
 * Generate BuiltWith firewall config.
 *
 * Data source: https://api.builtwith.com
 *
 * BuiltWith authenticates with an API key passed as the `KEY` query
 * parameter on every request.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://api.builtwith.com";
// Format: 32 hex chars
const PLACEHOLDER_VALUE = "c0ffeesafelocal5afe10ca1c0ffeesa";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from BuiltWith API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:builtwith",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const builtwithFirewall = {",
    '  name: "builtwith",',
    '  description: "BuiltWith API",',
    "  placeholders: {",
    `    BUILTWITH_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.builtwith.com",',
    "      auth: {",
    "        query: {",
    '          KEY: "${{ secrets.BUILTWITH_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating BuiltWith firewall config...");
  const ts = generateTypeScript();
  writeOutput("builtwith", ts, import.meta.dirname);
}
